import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';

import constFlaskURL from '../../consts/constFlaskURL'
import { addRow } from '../../crud/crud';

import '../../App.css';
import '../../../node_modules/bootstrap/dist/css/bootstrap.css'


function AddRoad() {
    const [name_road, setName] = useState('');
    const [number_road, setNumber] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const handleLogout = async () => {
        setLoading(true);

        try 
        {
            const response = await constFlaskURL.post('/logout');

            if (response.status === 200) 
            {
                setTimeout(() => {
                    navigate('/login');
                }, 1000);
            }
        }
        catch (err) 
        {
            console.error('Logout error:', err);
        } 
        finally 
        {
            setLoading(false);
        }
    };

    const submitRoad = async (e) => {
        const road = { name_road, number_road };

        e.preventDefault();
        addRow('/roads', road);

        // try {
        //     const add_road = await constFlaskURL.post('/roads', road);

        //     if (add_road.status === 201){
        //         setName('');
        //         setNumber('');
        //         navigate('/roads');
        //     }
        // } catch (error) {
        //     console.log(error);
        // }
    };

    return (
        <div>
            <nav className="navbar navbar-expand-lg navbar-dark bg-dark flex-column align-items-start p-0">
                <div className="container-fluid py-2">
                    <Link className="navbar-brand fs-3 fw-bold" to="/main">Дорожное хозяйство</Link>
                    <div class="btn-group">
                        <button type="button" class="btn btn-info">Пользователь</button>
                        <button type="button" class="btn btn-info dropdown-toggle dropdown-toggle-split" data-bs-toggle="dropdown" aria-expanded="false">
                            <span class="visually-hidden">Переключатель выпадающего списка</span>
                        </button>
                        <ul class="dropdown-menu">
                            <li>
                                <a class="dropdown-item">
                                    <button
                                        onClick={handleLogout} 
                                        className='dropdown-item'
                                        disabled={loading}
                                    >
                                        {loading ? (
                                            <>
                                                <span className='spinner'></span>
                                                Выход...
                                            </>
                                        ) : 'Выйти'}
                                    </button>
                                </a>
                            </li>
                        </ul>
                    </div>
                </div>
            </nav>
            <form className='container' onSubmit={submitRoad}>
                <h1>Создание дороги</h1>
                <div className='mb-3'>
                    <lable className='form-label'>Название дороги</lable>
                    <input 
                        type='text'
                        name='name_road' 
                        value={name_road.name_road} 
                        // onChange={(e) => setName(e.target.value)}
                        className='form-input'  
                        placeholder='Название дороги'
                        required  
                    />
                </div>
                <div className='mb-3'>
                    <lable className='form-label'>Номер дороги</lable>
                    <input 
                        type='text'
                        name='number_road' 
                        value={number_road.number_road} 
                        // onChange={(e) => setNumber(e.target.value)}
                        className='form-input'  
                        placeholder='Номер дорожного знака'
                        required  
                    />
                </div>
                <button 
                    type='submit' 
                    className='btn btn-primary'
                >
                    Добавить
                </button>
                <button 
                    type='submit' 
                    className='btn btn-danger' 
                    onClick={() => navigate('/roads')}
                >
                    Назад
                </button>
            </form>
        </div>
    )

};

export default AddRoad;
